        @mcp.tool()
        async def ocr_recognise_from_url(url: str, output_filename: str | None = None) -> dict:
            """
            Recognise text from an image located at a remote URL using Aspose.OCR.
        
            IMPORTANT:
            * All *_filename parameters accept ONLY the bare filename (e.g. 'scan.jpg') — no path, no directory, no drive letter, no slash.
            * The file MUST already exist in the server's ASPOSE_FILES_PATH folder before calling this tool.
            * Do NOT ask the user to upload a file — files are pre‑placed in the server folder by the user.
            * The output file is also written to the ASPOSE_FILES_PATH folder; the returned output_filename is the bare name only.
        
            Args:
                url: Full URL of the image to download and recognise.
                output_filename: Bare filename for the OCR result text file. If ``None``, a temporary
                                 filename is generated automatically.
        
            Returns:
                dict: {
                    "status": "success" | "error",
                    "message": str,
                    "text": str,               # recognised text (empty on error)
                    "output_filename": str     # bare name of the written result file
                }
        
            Raises:
                ValueError: If the provided URL is empty or malformed.
                FileNotFoundError: If the temporary download fails.
                Exception: Any unexpected error from Aspose.OCR.
        
            Example:
                >>> await ocr_recognise_from_url(
                ...     url="https://example.com/image.png",
                ...     output_filename="result.txt"
                ... )
                {"status":"success","message":"OCR completed","text":"Hello world","output_filename":"result.txt"}
            """
            # ----------------------------------------------------------------------
            # Validate and sanitise the URL
            # ----------------------------------------------------------------------
            from urllib.parse import urlparse
        
            if not url or not isinstance(url, str):
                raise ValueError("URL must be a non‑empty string.")
            parsed = urlparse(url.strip())
            if not (parsed.scheme and parsed.netloc):
                raise ValueError(f"Invalid URL supplied: {url}")
        
            # ----------------------------------------------------------------------
            # Prepare a temporary file for the downloaded image
            # ----------------------------------------------------------------------
            from pathlib import Path
            from mcp_server.path_utils import temp_output_path, get_safe_path
            import aiohttp
            import logging
        
            logger = logging.getLogger(__name__)
        
            # Create a temporary path for the image download
            temp_image_path = str(temp_output_path("ocr_input", ".tmp"))
            # Ensure the directory exists
            Path(temp_image_path).parent.mkdir(parents=True, exist_ok=True)
        
            try:
                async with aiohttp.ClientSession() as session:
                    async with session.get(url) as resp:
                        if resp.status != 200:
                            raise ValueError(f"Failed to download image, HTTP status {resp.status}")
                        data = await resp.read()
                # Write the image bytes to the temporary file
                Path(temp_image_path).write_bytes(data)
            except Exception as exc:
                logger.error("Error downloading image from %s: %s", url, exc)
                raise FileNotFoundError(f"Could not download image from URL: {url}") from exc
        
            # ----------------------------------------------------------------------
            # Resolve the output filename
            # ----------------------------------------------------------------------
            if output_filename is not None:
                # sanitise
                output_filename = Path(output_filename.strip().replace('\x00', '')).name
                resolved_output = get_safe_path(output_filename)
            else:
                resolved_output = str(temp_output_path("aspose_ocr_result", ".txt"))
                output_filename = Path(resolved_output).name  # bare name for the return value
        
            # Ensure the output directory exists
            Path(resolved_output).parent.mkdir(parents=True, exist_ok=True)
        
            # ----------------------------------------------------------------------
            # Perform OCR using Aspose.OCR
            # ----------------------------------------------------------------------
            try:
                # Lazy import of Aspose OCR
                import aspose.ocr as ocr
        
                ocr_client = ocr.AsposeOcr()
                # Recognise text from the downloaded image file
                result = ocr_client.recognize(str(temp_image_path))
        
                recognised_text = getattr(result, "text", "")
                # Write recognised text to the output file
                Path(resolved_output).write_text(recognised_text, encoding="utf-8")
        
                return {
                    "status": "success",
                    "message": "OCR completed",
                    "text": recognised_text,
                    "output_filename": output_filename,
                }
            except Exception as exc:  # pragma: no cover – generic catch for Aspose errors
                logger.exception("Aspose OCR failed: %s", exc)
                return {
                    "status": "error",
                    "message": str(exc),
                    "text": "",
                    "output_filename": output_filename,
                }

        @mcp.tool()
        async def ocr_recognise_batch_folder(
            folder_folder_name: str,
            output_filename: str | None = None,
        ) -> dict:
            """
            Perform OCR on all images in a server‑side folder and optionally combine the results
            into a single text file.
        
            IMPORTANT: All *_filename parameters accept ONLY the bare filename (e.g. 'scan.jpg') —
            no path, no directory, no drive letter, no slash.
            The file MUST already exist in the server's ASPOSE_FILES_PATH folder.
            Do NOT ask the user to upload a file — files are pre‑placed in that folder.
            Output files are written to the same folder; returned output_filename is the bare name only.
        
            Args:
                folder_folder_name: Folder name only — e.g. 'scans'. Must exist under ASPOSE_FILES_PATH.
                output_filename: Output filename only for combined results. If None a temporary file is used.
        
            Returns:
                dict: {
                    "status": "success" | "error",
                    "message": str,
                    "results": [{"filename": str, "text": str}, ...],
                    "output_filename": str   # bare name of the file containing combined OCR text
                }
        
            Raises:
                FileNotFoundError: If the specified folder does not exist or contains no files.
                Exception: Propagated as an error status with message.
        
            Example:
                result = await ocr_recognise_batch_folder('scans', 'combined.txt')
                # result['results'] is a list of dicts with 'filename' and 'text' keys
            """
            # ----------------------------------------------------------------------
            # Resolve and validate inputs (must be done before any Aspose import)
            # ----------------------------------------------------------------------
            from pathlib import Path
            from mcp_server.path_utils import get_safe_path, temp_output_path
            import logging
        
            logger = logging.getLogger(__name__)
        
            # Sanitize folder name and resolve absolute path inside ASPOSE_FILES_PATH
            folder_folder_name = Path(folder_folder_name.strip().replace("\x00", "")).name
            resolved_folder = get_safe_path(folder_folder_name)
            if not Path(resolved_folder).is_dir():
                raise FileNotFoundError(f"Folder not found: {folder_folder_name}")
        
            # Resolve output filename (if provided) or create a temporary one
            if output_filename is not None:
                output_filename = Path(output_filename.strip().replace("\x00", "")).name
                resolved_output = get_safe_path(output_filename)
            else:
                # temporary file with .txt extension
                temp_path = temp_output_path("aspose_ocr_result", ".txt")
                resolved_output = str(temp_path)
                output_filename = Path(resolved_output).name
        
            # Ensure the output directory exists
            Path(resolved_output).parent.mkdir(parents=True, exist_ok=True)
        
            # ----------------------------------------------------------------------
            # Validate files in the folder before importing Aspose
            # ----------------------------------------------------------------------
            file_paths = [fp for fp in Path(resolved_folder).iterdir() if fp.is_file()]
            if not file_paths:
                raise FileNotFoundError(f"No files found in folder: {folder_folder_name}")
        
            # ----------------------------------------------------------------------
            # Perform OCR using Aspose
            # ----------------------------------------------------------------------
            try:
                import aspose.ocr as ocr
        
                engine = ocr.AsposeOcr()
                results: list[dict] = []
                combined_text_parts: list[str] = []
        
                for fp in file_paths:
                    # Prepare OCR input for a single image
                    inp = ocr.OcrInput(ocr.InputType.SINGLE_IMAGE)
                    inp.add(str(fp))
        
                    # Run recognition
                    out = engine.recognize(inp)
                    text = out[0].recognition_text if out else ""
        
                    results.append({"filename": fp.name, "text": text})
                    combined_text_parts.append(text)
        
                # Write combined results to the output file
                with open(resolved_output, "w", encoding="utf-8") as f:
                    f.write("\n".join(combined_text_parts))
        
                return {
                    "status": "success",
                    "message": f"OCR completed for folder '{folder_folder_name}'.",
                    "results": results,
                    "output_filename": output_filename,
                }
        
            except Exception as exc:  # pragma: no cover
                logger.exception("OCR batch processing failed")
                return {"status": "error", "message": str(exc)}

        @mcp.tool()
        async def ocr_get_result_as_text(
            image_filename: str,
            output_filename: str | None = None,
        ) -> dict:
            """
            Extract text from an image stored on the server using Aspose OCR.
        
            IMPORTANT:
            * All *_filename parameters accept ONLY the bare filename (e.g. 'scan.jpg') — no path, no directory, no drive letter, no slash.
            * The file MUST already exist in the server's ASPOSE_FILES_PATH folder before calling this tool.
            * Do NOT ask the user to upload a file — files are pre‑placed in the server folder by the user.
            * The output file is also written to the ASPOSE_FILES_PATH folder; the returned output_filename is the bare name only.
        
            Args:
                image_filename: Bare filename of the image to process, e.g. 'document.png' — must already exist in ASPOSE_FILES_PATH.
                output_filename: Optional bare filename for saving the raw OCR JSON result. If omitted, a temporary file is used.
        
            Returns:
                dict: {
                    "status": "success" | "error",
                    "message": str,
                    "text": str,               # extracted plain text (empty if none)
                    "output_filename": str | None  # bare name of the JSON file if written, otherwise None
                }
        
            Raises:
                FileNotFoundError: If the specified image file does not exist.
                RuntimeError: If OCR processing yields no result.
        
            Example:
                >>> result = await ocr_get_result_as_text("invoice.jpg", "invoice_ocr.json")
                >>> print(result["text"])
            """
            # -------------------------------------------------------------------------
            # Resolve and validate input file(s)
            # -------------------------------------------------------------------------
            from pathlib import Path
            from mcp_server.path_utils import get_safe_path, temp_output_path
            import logging
            import json
        
            # sanitize and resolve the image file
            image_filename = Path(image_filename.strip().replace('\x00', '')).name
            resolved_image = get_safe_path(image_filename)
            if not Path(resolved_image).is_file():
                raise FileNotFoundError(f"File not found: {image_filename}")
        
            # -------------------------------------------------------------------------
            # Resolve optional output file
            # -------------------------------------------------------------------------
            if output_filename is not None:
                output_filename = Path(output_filename.strip().replace('\x00', '')).name
            resolved_output = (
                get_safe_path(output_filename)
                if output_filename
                else str(temp_output_path("aspose_ocr_result", ".json"))
            )
            Path(resolved_output).parent.mkdir(parents=True, exist_ok=True)
        
            # -------------------------------------------------------------------------
            # Perform OCR using Aspose
            # -------------------------------------------------------------------------
            try:
                import aspose.ocr as ocr
        
                engine = ocr.OcrEngine()
                # Recognize the image; the method returns a RecognitionResult object
                result = engine.recognize_image(str(resolved_image))
                if result is None:
                    raise RuntimeError("No OCR result returned")
        
                # Get JSON representation and extract plain text
                json_str = result.get_json()
                data = json.loads(json_str)
                text = data.get("text", "")
        
                # Write raw JSON to the output file if requested
                if output_filename is not None:
                    with open(resolved_output, "w", encoding="utf-8") as f:
                        f.write(json_str)
        
                return {
                    "status": "success",
                    "message": "OCR completed successfully",
                    "text": text,
                    "output_filename": output_filename,
                }
        
            except Exception as exc:  # pragma: no cover
                logging.getLogger(__name__).error("OCR processing failed: %s", exc)
                return {"status": "error", "message": str(exc)}

