            # ----------------------------------------------------------------------
            import logging
            logger = logging.getLogger(__name__)
        
            # ----------------------------------------------------------------------
            # Perform OCR using Aspose.OCR
            # ----------------------------------------------------------------------
            try:
                import aspose.ocr as ocr
        
                # Create OCR engine instance
                ocr_engine = ocr.AsposeOcr()
        
                # Recognize the image
                recognition_result = ocr_engine.recognize(str(resolved_input))
        
                # Extract words and their bounding boxes
                words_list: list[dict] = []
                for word_obj in getattr(recognition_result, "words", []):
                    text = getattr(word_obj, "text", "")
                    # Bounding box may be exposed as 'bounding_box' or 'rectangle'
                    bbox_source = getattr(word_obj, "bounding_box", None) or getattr(word_obj, "rectangle", None)
                    if bbox_source:
                        x = getattr(bbox_source, "x", 0)
                        y = getattr(bbox_source, "y", 0)
                        width = getattr(bbox_source, "width", 0)
                        height = getattr(bbox_source, "height", 0)
                        bbox = [x, y, width, height]
                    else:
                        bbox = []
                    words_list.append({"text": text, "bbox": bbox})
        
                return {
                    "status": "success",
                    "message": "OCR completed successfully.",
                    "words": words_list,
                }
        
            except Exception as exc:  # pragma: no cover
                logger.exception("OCR processing failed")
                return {"status": "error", "message": str(exc)}

