        @mcp.tool()
        async def ocr_save_result_to_pdf(
            image_filename: str,
            output_filename: str,
        ) -> dict:
            """
            Convert a single image to a searchable PDF using Aspose OCR.
        
            IMPORTANT:
            All *_filename parameters accept ONLY the bare filename (e.g. 'scan.jpg') — no path,
            no directory, no drive letter, no slash.
            The file MUST already exist in the server's ASPOSE_FILES_PATH folder before calling this tool.
            Do NOT ask the user to upload a file — files are pre‑placed in the server folder by the user.
            The output file is also written to the ASPOSE_FILES_PATH folder; the returned output_filename is the bare name only.
        
            Args:
                image_filename: Bare filename of the source image — must already exist in ASPOSE_FILES_PATH.
                output_filename: Bare filename for the output PDF, e.g. 'result.pdf'.
        
            Returns:
                dict: {
                    "status": "success" | "error",
                    "message": str,
                    "output_filename": str   # bare name of the written PDF (if successful)
                }
        
            Raises:
                FileNotFoundError: If the specified image file does not exist.
        
            Example:
                >>> await ocr_save_result_to_pdf("photo.jpg", "photo_result.pdf")
                {"status": "success", "message": "OCR result saved to PDF.", "output_filename": "photo_result.pdf"}
            """
            # -------------------------------------------------------------------------
            # Non‑Aspose imports and initial validation (must be before any Aspose import)
            # -------------------------------------------------------------------------
            import logging
            from pathlib import Path
            from mcp_server.path_utils import get_safe_path, temp_output_path
        
            logger = logging.getLogger(__name__)
        
            # Sanitize and resolve the input image filename
            image_filename = Path(image_filename.strip().replace("\x00", "")).name
            resolved_input = get_safe_path(image_filename)
            if not Path(resolved_input).is_file():
                raise FileNotFoundError(f"File not found: {image_filename}")
        
            # Sanitize and resolve the output PDF filename
            if output_filename is not None:
                output_filename = Path(output_filename.strip().replace("\x00", "")).name
            resolved_output = (
                get_safe_path(output_filename)
                if output_filename
                else str(temp_output_path("aspose_ocr_result", ".pdf"))
            )
            Path(resolved_output).parent.mkdir(parents=True, exist_ok=True)
        
            # -------------------------------------------------------------------------
            # Aspose OCR processing
            # -------------------------------------------------------------------------
            import aspose.ocr as ocr
        
            try:
                engine = ocr.AsposeOcr()
                inp = ocr.OcrInput(ocr.InputType.SINGLE_IMAGE)
                inp.add(str(resolved_input))
        
                results = engine.recognize(inp)
        
                # Save the OCR results as a multi‑page PDF
                ocr.AsposeOcr.save_multipage_document(
                    str(resolved_output), ocr.SaveFormat.PDF, results
                )
        
                return {
                    "status": "success",
                    "message": "OCR result saved to PDF.",
                    "output_filename": output_filename,
                }
            except Exception as exc:  # pragma: no cover
                logger.exception("Error during OCR PDF conversion")
                return {"status": "error", "message": str(exc)}

        @mcp.tool()
        async def ocr_save_result_to_docx(output_filename: str) -> dict:
            """
            Save a previously generated OCR RecognitionResult to a DOCX file.
        
            IMPORTANT:
            * All *_filename parameters accept ONLY the bare filename (e.g. 'scan.jpg') — no path, no directory, no drive letter, no slash.
            * The file MUST already exist in the server's ASPOSE_FILES_PATH folder before calling this tool.
            * Do NOT ask the user to upload a file — files are pre‑placed in the server folder by the user.
            * The output file is also written to the ASPOSE_FILES_PATH folder; the returned output_filename is the bare name only.
        
            Args:
                output_filename: str
                    Bare filename for the DOCX file to be created (e.g. 'result.docx').
        
            Returns:
                dict: {
                    "status": "success" | "error",
                    "message": str,
                    "output_filename": str   # bare name of the written DOCX file (present only on success)
                }
        
            Raises:
                FileNotFoundError: If the intermediate OCR result file cannot be found.
                RuntimeError: If there is no OCR result to save.
        
            Example:
                >>> await ocr_save_result_to_docx("my_scan.docx")
                {"status":"success","message":"OCR result saved to DOCX.","output_filename":"my_scan.docx"}
            """
            # ----------------------------------------------------------------------
            # Resolve and sanitize the output filename (no Aspose import yet)
            # ----------------------------------------------------------------------
            from pathlib import Path
            from mcp_server.path_utils import get_safe_path, temp_output_path
            import logging
        
            logger = logging.getLogger(__name__)
        
            # sanitize the caller‑provided name
            output_filename = Path(output_filename.strip().replace('\x00', '')).name
        
            # resolve the absolute path where the DOCX will be written
            resolved_output = (
                get_safe_path(output_filename)
                if output_filename
                else str(temp_output_path("aspose_ocr_result", ".docx"))
            )
            # ensure the target directory exists
            Path(resolved_output).parent.mkdir(parents=True, exist_ok=True)
        
            # ----------------------------------------------------------------------
            # Locate the intermediate OCR result (generated by a previous OCR step)
            # ----------------------------------------------------------------------
            # The OCR engine stores its RecognitionResult in a binary file named
            # "ocr_result.bin" inside ASPOSE_FILES_PATH. This file must exist.
            default_result_name = "ocr_result.bin"
            resolved_result = get_safe_path(default_result_name)
            if not Path(resolved_result).is_file():
                msg = f"OCR result file not found: {default_result_name}"
                logger.error(msg)
                raise FileNotFoundError(msg)
        
            # ----------------------------------------------------------------------
            # Load the RecognitionResult and save it as DOCX
            # ----------------------------------------------------------------------
            try:
                import aspose.ocr as ocr
        
                # Create a RecognitionResult instance and load the binary data.
                # Aspose.OCR provides a parameter‑less constructor; we then use the
                # `load` method (if present) to populate it from the saved file.
                result = ocr.RecognitionResult()
                if hasattr(result, "load"):
                    result.load(str(resolved_result))
                else:
                    # Fallback: some SDK versions expose a static `load` method.
                    # Attempt to call it directly on the class.
                    load_func = getattr(ocr.RecognitionResult, "load", None)
                    if callable(load_func):
                        result = load_func(str(resolved_result))
                    else:
                        raise RuntimeError("RecognitionResult cannot be loaded from a file.")
        
                # Save the OCR result to the requested DOCX location.
                result.save(str(resolved_output))
            except Exception as exc:  # pragma: no cover – generic catch as required
                logger.exception("Failed to save OCR result to DOCX")
                return {"status": "error", "message": str(exc)}
        
            return {
                "status": "success",
                "message": "OCR result saved to DOCX.",
                "output_filename": output_filename,
            }

