        @mcp.tool()
        async def ocr_set_recognition_area(
            left: int,
            top: int,
            width: int,
            height: int,
        ) -> dict:
            """
            Set a custom recognition area for OCR processing.
        
            IMPORTANT:
            * All *_filename parameters accept ONLY the bare filename (e.g. 'scan.jpg') — no path, no directory, no drive letter, no slash.
            * The file MUST already exist in the server's ASPOSE_FILES_PATH folder before calling this tool.
            * Do NOT ask the user to upload a file — files are pre‑placed in the server folder by the user.
            * The output file is also written to the ASPOSE_FILES_PATH folder; the returned output_filename is the bare name only.
        
            Args:
                left (int): Left edge of the recognition area in pixels.
                top (int): Top edge of the recognition area in pixels.
                width (int): Width of the recognition area in pixels.
                height (int): Height of the recognition area in pixels.
        
            Returns:
                dict: {
                    "status": "success" | "error",
                    "message": str
                }
        
            Raises:
                ValueError: If any dimension is non‑positive or if the rectangle is invalid.
                Exception: For unexpected errors from the Aspose OCR library.
        
            Example:
                >>> result = await ocr_set_recognition_area(left=10, top=20, width=200, height=100)
                >>> print(result)
                {'status': 'success', 'message': 'Recognition area set successfully.'}
            """
            # Validate dimensions before importing Aspose
            if width <= 0 or height <= 0:
                raise ValueError("Width and height must be positive integers.")
            if left < 0 or top < 0:
                raise ValueError("Left and top coordinates must be non‑negative integers.")
        
            import logging
            from aspose.ocr import RecognitionSettings, Rectangle
        
            logger = logging.getLogger(__name__)
        
            try:
                # Create a new RecognitionSettings instance and assign the custom area
                settings = RecognitionSettings()
                rect = Rectangle(left, top, width, height)
                # The Aspose OCR API expects a list of rectangles for the recognition_areas property
                settings.recognition_areas = [rect]
        
                # In a real scenario the settings would be applied to an OCR engine instance.
                # Here we simply confirm that the operation succeeded.
                logger.debug(
                    "Set OCR recognition area to left=%d, top=%d, width=%d, height=%d",
                    left,
                    top,
                    width,
                    height,
                )
                return {"status": "success", "message": "Recognition area set successfully."}
            except Exception as exc:  # pragma: no cover
                logger.exception("Failed to set OCR recognition area.")
                return {"status": "error", "message": str(exc)}

