        async def ocr_detect_skew(image_filename: str, output_filename: str | None = None) -> dict:
            """
            Detect and correct the skew of an image stored on the server.
        
            IMPORTANT:
            All *_filename parameters accept ONLY the bare filename (e.g. 'scan.jpg') — no path, no directory, no drive letter, no slash.
            The file MUST already exist in the server's ASPOSE_FILES_PATH folder before calling this tool.
            Do NOT ask the user to upload a file — files are pre‑placed in the server folder by the user.
            The output file is also written to the ASPOSE_FILES_PATH folder; the returned output_filename is the bare name only.
        
            Args:
                image_filename: Bare filename of the source image, e.g. 'tilted.jpg'.
                output_filename: Optional bare filename for the deskewed image. If omitted, a temporary file is created.
        
            Returns:
                dict: {
                    "status": "success" | "error",
                    "message": str,
                    "skew_angle": float,          # detected skew angle in degrees
                    "output_filename": str        # bare name of the corrected image
                }
        
            Raises:
                FileNotFoundError: If the source image does not exist.
                Exception: Any unexpected error from Aspose OCR processing.
        
            Example:
                result = await ocr_detect_skew("tilted.jpg", "straightened.jpg")
                # result["skew_angle"] might be -2.5, result["output_filename"] == "straightened.jpg"
            """
            # -------------------------------------------------------------------------
            # Resolve and validate input / output filenames before any Aspose import
            # -------------------------------------------------------------------------
            from pathlib import Path
            from mcp_server.path_utils import get_safe_path, temp_output_path
            import logging
        
            logger = logging.getLogger(__name__)
        
            # sanitize and resolve the input image
            image_filename = Path(image_filename.strip().replace('\x00', '')).name
            resolved_input = get_safe_path(image_filename)
            if not Path(resolved_input).is_file():
                raise FileNotFoundError(f"File not found: {image_filename}")
        
            # prepare the output location
            if output_filename is not None:
                output_filename = Path(output_filename.strip().replace('\x00', '')).name
                resolved_output = get_safe_path(output_filename)
            else:
                # generate a temporary filename (PNG) inside ASPOSE_FILES_PATH
                temp_path = temp_output_path("aspose_ocr_skew", ".png")
                resolved_output = str(temp_path)
                output_filename = Path(resolved_output).name
        
            # ensure the output directory exists
            Path(resolved_output).parent.mkdir(parents=True, exist_ok=True)
        
            # -------------------------------------------------------------------------
            # Aspose OCR processing (imported lazily after validation)
            # -------------------------------------------------------------------------
            import aspose.ocr as ocr
        
            try:
                ocr_engine = ocr.AsposeOcr()
                # calc_skew_image returns the detected skew angle (float) and writes the corrected image
                skew_angle = ocr_engine.calc_skew_image(resolved_input, resolved_output)
        
                logger.info(
                    "Skew detection completed for %s (angle=%s)",
                    image_filename,
                    skew_angle,
                )
                return {
                    "status": "success",
                    "message": "Skew detection and correction completed.",
                    "skew_angle": float(skew_angle),
                    "output_filename": output_filename,
                }
            except Exception as exc:  # pragma: no cover
                logger.exception("Error during OCR skew detection")
                return {"status": "error", "message": str(exc)}

